SELECT ?movie WHERE {
  ?movie wdt:P31 wd:Q11424;
         wdt:P1476 ?title.
  FILTER (lang(?title) = 'en').
  FILTER (CONTAINS(lcase(?title), "bad boys for life"))
}

SELECT ?award ?awardLabel WHERE {
  wd:Q29021224 wdt:P1545 ?award.
